**Notification Hook**

```typescript
// src/hooks/useNotification.hook.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { HTMLHuelNotificationElement } from 'huel-notification';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext<HTMLHuelNotificationElement | null>(null);

export const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);

  useEffect(() => {
    if (notificationElem && !isNotificationOpen) {
      setIsNotificationOpen(true);
    }
  }, [notificationElem, isNotificationOpen]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    try {
      await notificationElem.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      console.error(error);
    }
  };

  return { notify, isNotificationOpen };
};

export default NotificationContext;
```

